const INDEX_DDL = [
    `CREATE INDEX IDX_DFE_DOC_CNPJ_EMP ON DFE_NFE_DOCUMENTO(CNPJ_EMPRESA)`,
    `CREATE INDEX IDX_DFE_DOC_EMITENTE ON DFE_NFE_DOCUMENTO(CNPJ_EMITENTE)`,
    `CREATE INDEX IDX_DFE_DOC_STATUS ON DFE_NFE_DOCUMENTO(STATUS_ENTRADA)`,
    `CREATE INDEX IDX_DFE_DOC_EMISSAO ON DFE_NFE_DOCUMENTO(DATA_EMISSAO)`,
    `CREATE INDEX IDX_DFE_ITEM_DFE ON DFE_NFE_ITEM(ID_DFE)`,
    `CREATE INDEX IDX_DFE_ITEM_CHAVE ON DFE_NFE_ITEM(CHAVE_NFE)`,
    `CREATE INDEX IDX_DFE_ITEM_EAN ON DFE_NFE_ITEM(EAN_COMERCIAL)`,
    `CREATE INDEX IDX_DFE_EVENTO_CHAVE ON DFE_NFE_EVENTO(CHAVE_NFE)`,
    `CREATE INDEX IDX_DFE_LOG_CHAVE ON DFE_LOG_PROCESSO(CHAVE_NFE)`,
];

export async function ensureFiscalRadarTables() {
    if (!isOracleEnabled() || initialized) return;
    for (const t of TABLE_DDL) {
        try {
            await execDml(t.ddl);
        } catch (e) {
            if (e?.errorNum !== 955 && e?.errorNum !== 2264) {
                console.warn(`ensureFiscalRadarTables [${t.name}]:`, e?.code || e?.message?.slice(0, 80));
            }
        }
    }
    for (const idx of INDEX_DDL) {
        try { await execDml(idx); } catch (_) { /* already exists */ }
    }
    initialized = true;
}
